{"meta": null, "content": [{"type": "text", "text": "{"content":"1: package api\n2: \n3: import (\n4: \t\"context\"\n5: \t\"net/http\"\n6: \t\"time\"\n7: \n8: \t\"github.com/grafana/grafana/pkg/api/response\"\n9: \t\"github.com/grafana/grafana/pkg/apimachinery/identity\"\n10: \tac \"github.com/grafana/grafana/pkg/services/accesscontrol\"\n11: \tcontextmodel \"github.com/grafana/grafana/pkg/services/contexthandler/model\"\n12: \t\"github.com/grafana/grafana/pkg/services/stats\"\n13: \t\"github.com/grafana/grafana/pkg/setting\"\n14: )\n15: \n16: // swagger:route GET /admin/settings admin adminGetSettings\n17: //\n18: // Fetch settings.\n19: //\n20: // If you are running Grafana Enterprise and have Fine-grained access control enabled, you need to have a permission with action `settings:read` and scopes: `settings:*`, `settings:auth.saml:` and `settings:auth.saml:enabled` (property level).\n21: //\n22: // Security:\n23: // - basic:\n24: //\n25: // Responses:\n26: // 200: adminGetSettingsResponse\n27: // 401: unauthorisedError\n28: // 403: forbiddenError\n29: func (hs *HTTPServer) AdminGetSettings(c *contextmodel.ReqContext) response.Response {\n30: \tsettings, err := hs.getAuthorizedSettings(c.Req.Context(), c.SignedInUser, hs.SettingsProvider.Current())\n31: \tif err != nil {\n32: \t\treturn response.Error(http.StatusForbidden, \"Failed to authorize settings\", err)\n33: \t}\n34: \treturn response.JSON(http.StatusOK, settings)\n35: }\n36: \n37: func (hs *HTTPServer) AdminGetVerboseSettings(c *contextmodel.ReqContext) response.Response {\n38: \tbag := hs.SettingsProvider.CurrentVerbose()\n39: \tif bag == nil {\n40: \t\treturn response.JSON(http.StatusNotImplemented, make(map[string]string))\n41: \t}\n42: \n43: \tverboseSettings, err := hs.getAuthorizedVerboseSettings(c.Req.Context(), c.SignedInUser, bag)\n44: \tif err != nil {\n45: \t\treturn response.Error(http.StatusForbidden, \"Failed to authorize settings\", err)\n46: \t}\n47: \treturn response.JSON(http.StatusOK, verboseSettings)\n48: }\n49: \n50: // swagger:route GET /admin/stats admin adminGetStats\n51: //\n52: // Fetch Grafana Stats.\n53: //\n54: // Only works with Basic Authentication (username and password). See introduction for an explanation.\n55: // If you are running Grafana Enterprise and have Fine-grained access control enabled, you need to have a permission with action `server:stats:read`.\n56: //\n57: // Responses:\n58: // 200: adminGetStatsResponse\n59: // 401: unauthorisedError\n60: // 403: forbiddenError\n61: // 500: internalServerError\n62: func (hs *HTTPServer) AdminGetStats(c *contextmodel.ReqContext) response.Response {\n63: \tadminStats, err := hs.statsService.GetAdminStats(c.Req.Context(), \u0026stats.GetAdminStatsQuery{})\n64: \tif err != nil {\n65: \t\treturn response.Error(http.StatusInternalServerError, \"Failed to get admin stats from database\", err)\n66: \t}\n67: \tanonymousDeviceExpiration := 30 * 24 * time.Hour\n68: \tdevicesCount, err := hs.anonService.CountDevices(c.Req.Context(), time.Now().Add(-anonymousDeviceExpiration), time.Now().Add(time.Minute))\n69: \tif err != nil {\n70: \t\treturn response.Error(http.StatusInternalServerError, \"Failed to get anon stats from database\", err)\n71: \t}\n72: \tadminStats.ActiveDevices = devicesCount\n73: \n74: \treturn response.JSON(http.StatusOK, adminStats)\n75: }\n76: \n77: func (hs *HTTPServer) getAuthorizedSettings(ctx context.Context, user identity.Requester, bag setting.SettingsBag) (setting.SettingsBag, error) {\n78: \teval := func(scope string) (bool, error) {\n79: \t\treturn hs.AccessControl.Evaluate(ctx, user, ac.EvalPermission(ac.ActionSettingsRead, scope))\n80: \t}\n81: \n82: \tok, err := eval(ac.ScopeSettingsAll)\n83: \tif err != nil {\n84: \t\treturn nil, err\n85: \t}\n86: \tif ok {\n87: \t\treturn bag, nil\n88: \t}\n89: \n90: \tauthorizedBag := make(setting.SettingsBag)\n91: \n92: \tfor section, keys := range bag {\n93: \t\tok, err := eval(ac.Scope(\"settings\", section, \"*\"))\n94: \t\tif err != nil {\n95: \t\t\treturn nil, err\n96: \t\t}\n97: \t\tif ok {\n98: \t\t\tauthorizedBag[section] = keys\n99: \t\t\tcontinue\n100: \t\t}\n101: \n102: \t\tfor key := range keys {\n103: \t\t\tok, err := eval(ac.Scope(\"settings\", section, key))\n104: \t\t\tif err != nil {\n105: \t\t\t\treturn nil, err\n106: \t\t\t}\n107: \t\t\tif ok {\n108: \t\t\t\tif _, exists := authorizedBag[section]; !exists {\n109: \t\t\t\t\tauthorizedBag[section] = make(map[string]string)\n110: \t\t\t\t}\n111: \t\t\t\tauthorizedBag[section][key] = bag[section][key]\n112: \t\t\t}\n113: \t\t}\n114: \t}\n115: \treturn authorizedBag, nil\n116: }\n117: \n118: func (hs *HTTPServer) getAuthorizedVerboseSettings(ctx context.Context, user identity.Requester, bag setting.VerboseSettingsBag) (setting.VerboseSettingsBag, error) {\n119: \teval := func(scope string) (bool, error) {\n120: \t\treturn hs.AccessControl.Evaluate(ctx, user, ac.EvalPermission(ac.ActionSettingsRead, scope))\n121: \t}\n122: \n123: \tok, err := eval(ac.ScopeSettingsAll)\n124: \tif err != nil {\n125: \t\treturn nil, err\n126: \t}\n127: \tif ok {\n128: \t\treturn bag, nil\n129: \t}\n130: \n131: \tauthorizedBag := make(setting.VerboseSettingsBag)\n132: \n133: \tfor section, keys := range bag {\n134: \t\tok, err := eval(ac.Scope(\"settings\", section, \"*\"))\n135: \t\tif err != nil {\n136: \t\t\treturn nil, err\n137: \t\t}\n138: \t\tif ok {\n139: \t\t\tauthorizedBag[section] = keys\n140: \t\t\tcontinue\n141: \t\t}\n142: \n143: \t\tfor key := range keys {\n144: \t\t\tok, err := eval(ac.Scope(\"settings\", section, key))\n145: \t\t\tif err != nil {\n146: \t\t\t\treturn nil, err\n147: \t\t\t}\n148: \n149: \t\t\tif !ok {\n150: \t\t\t\tcontinue\n151: \t\t\t}\n152: \n153: \t\t\tif _, exists := authorizedBag[section]; !exists {\n154: \t\t\t\tauthorizedBag[section] = make(map[string]map[setting.VerboseSourceType]string)\n155: \t\t\t}\n156: \t\t\tauthorizedBag[section][key] = bag[section][key]\n157: \t\t}\n158: \t}\n159: \n160: \treturn authorizedBag, nil\n161: }\n162: \n163: // swagger:response adminGetSettingsResponse\n164: type GetSettingsResponse struct {\n165: \t// in:body\n166: \tBody setting.SettingsBag `json:\"body\"`\n167: }\n168: \n169: // swagger:response adminGetStatsResponse\n170: type GetStatsResponse struct {\n171: \t// in:body\n172: \tBody stats.AdminStats `json:\"body\"`\n173: }\n174: ","url":"https://sourcegraph.sourcegraph.com/github.com/sg-evals/grafana--26d36ec@7b5876467dc156dd3117dd0b3c15f994100e9597/-/blob/pkg/api/admin.go"}", "annotations": null, "meta": null}], "structuredContent": {"content": "1: package api
