37: func (hs *HTTPServer) AdminGetVerboseSettings(c *contextmodel.ReqContext) response.Response {
38: 	bag := hs.SettingsProvider.CurrentVerbose()
39: 	if bag == nil {
40: 		return response.JSON(http.StatusNotImplemented, make(map[string]string))
41: 	}
42: 
43: 	verboseSettings, err := hs.getAuthorizedVerboseSettings(c.Req.Context(), c.SignedInUser, bag)
44: 	if err != nil {
45: 		return response.Error(http.StatusForbidden, "Failed to authorize settings", err)
46: 	}
47: 	return response.JSON(http.StatusOK, verboseSettings)
48: }
