50: // swagger:route GET /admin/stats admin adminGetStats
51: //
52: // Fetch Grafana Stats.
53: //
54: // Only works with Basic Authentication (username and password). See introduction for an explanation.
55: // If you are running Grafana Enterprise and have Fine-grained access control enabled, you need to have a permission with action `server:stats:read`.
56: //
57: // Responses:
58: // 200: adminGetStatsResponse
59: // 401: unauthorisedError
60: // 403: forbiddenError
61: // 500: internalServerError
62: func (hs *HTTPServer) AdminGetStats(c *contextmodel.ReqContext) response.Response {
63: 	adminStats, err := hs.statsService.GetAdminStats(c.Req.Context(), &stats.GetAdminStatsQuery{})
64: 	if err != nil {
65: 		return response.Error(http.StatusInternalServerError, "Failed to get admin stats from database", err)
66: 	}
67: 	anonymousDeviceExpiration := 30 * 24 * time.Hour
68: 	devicesCount, err := hs.anonService.CountDevices(c.Req.Context(), time.Now().Add(-anonymousDeviceExpiration), time.Now().Add(time.Minute))
69: 	if err != nil {
70: 		return response.Error(http.StatusInternalServerError, "Failed to get anon stats from database", err)
71: 	}
72: 	adminStats.ActiveDevices = devicesCount
73: 
74: 	return response.JSON(http.StatusOK, adminStats)
75: }
