77: func (hs *HTTPServer) getAuthorizedSettings(ctx context.Context, user identity.Requester, bag setting.SettingsBag) (setting.SettingsBag, error) {
78: 	eval := func(scope string) (bool, error) {
79: 		return hs.AccessControl.Evaluate(ctx, user, ac.EvalPermission(ac.ActionSettingsRead, scope))
80: 	}
81: 
82: 	ok, err := eval(ac.ScopeSettingsAll)
83: 	if err != nil {
84: 		return nil, err
85: 	}
86: 	if ok {
87: 		return bag, nil
88: 	}
89: 
90: 	authorizedBag := make(setting.SettingsBag)
91: 
92: 	for section, keys := range bag {
93: 		ok, err := eval(ac.Scope("settings", section, "*"))
94: 		if err != nil {
95: 			return nil, err
96: 		}
97: 		if ok {
98: 			authorizedBag[section] = keys
99: 			continue
100: 		}
101: 
102: 		for key := range keys {
103: 			ok, err := eval(ac.Scope("settings", section, key))
104: 			if err != nil {
105: 				return nil, err
106: 			}
107: 			if ok {
108: 				if _, exists := authorizedBag[section]; !exists {
