118: func (hs *HTTPServer) getAuthorizedVerboseSettings(ctx context.Context, user identity.Requester, bag setting.VerboseSettingsBag) (setting.VerboseSettingsBag, error) {
119: 	eval := func(scope string) (bool, error) {
120: 		return hs.AccessControl.Evaluate(ctx, user, ac.EvalPermission(ac.ActionSettingsRead, scope))
121: 	}
122: 
123: 	ok, err := eval(ac.ScopeSettingsAll)
124: 	if err != nil {
125: 		return nil, err
126: 	}
127: 	if ok {
128: 		return bag, nil
129: 	}
130: 
131: 	authorizedBag := make(setting.VerboseSettingsBag)
132: 
133: 	for section, keys := range bag {
134: 		ok, err := eval(ac.Scope("settings", section, "*"))
135: 		if err != nil {
136: 			return nil, err
137: 		}
138: 		if ok {
139: 			authorizedBag[section] = keys
140: 			continue
141: 		}
142: 
143: 		for key := range keys {
144: 			ok, err := eval(ac.Scope("settings", section, key))
145: 			if err != nil {
146: 				return nil, err
147: 			}
148: 
149: 			if !ok {
150: 				continue
151: 			}
152: 
153: 			if _, exists := authorizedBag[section]; !exists {
154: 				authorizedBag[section] = make(map[string]map[setting.VerboseSourceType]string)
155: 			}
156: 			authorizedBag[section][key] = bag[section][key]
157: 		}
158: 	}
159: 
160: 	return authorizedBag, nil
161: }
