1576: func (s *DynamicSection) Key(k string) *ini.Key {
1577: 	envKey := EnvKey(s.section.Name(), k)
1578: 	envValue := s.env.Getenv(envKey)
1579: 	key := s.section.Key(k)
1580: 
1581: 	if len(envValue) == 0 {
1582: 		return key
