8: // QuickRanges is a slice of QuickRange objects that can be directly used in frontend
9: type QuickRanges []QuickRange
10: 
11: // QuickRange represents a time range option in the time picker.
12: // It defines a preset time range that users can select from the time picker dropdown.
13: type QuickRange struct {
14: 	// Display is the user-friendly label shown in the UI for this time range
15: 	Display string `json:"display"`
16: 	// From is the start of the time range in a format like "now-6h" or an absolute time
17: 	From string `json:"from"`
18: 	// To is the end of the time range, defaults to "now" if omitted
19: 	To string `json:"to,omitempty"`
20: }
