22: func (cfg *Cfg) readTimePicker() error {
23: 	timePickerSection := cfg.Raw.Section("time_picker")
24: 	quickRangesStr := timePickerSection.Key("quick_ranges").String()
25: 
26: 	if quickRangesStr == "" {
27: 		cfg.QuickRanges = []QuickRange{}
28: 		return nil
29: 	}
30: 
31: 	var quickRanges []QuickRange
32: 	err := json.Unmarshal([]byte(quickRangesStr), &quickRanges)
33: 	if err != nil {
34: 		cfg.Logger.Error("Failed to parse quick_ranges", "error", err)
35: 		return fmt.Errorf("failed to parse quick_ranges: %w", err)
36: 	}
37: 
38: 	// Validate the quick ranges and set defaults
39: 	for i, qr := range quickRanges {
40: 		if qr.Display == "" {
41: 			cfg.Logger.Error("Quick range is missing display name", "index", i)
42: 			return fmt.Errorf("quick range at index %d is missing display name", i)
43: 		}
44: 		if qr.From == "" {
45: 			cfg.Logger.Error("Quick range is missing 'from' field", "display", qr.Display)
46: 			return fmt.Errorf("quick range '%s' is missing 'from' field", qr.Display)
47: 		}
48: 		// Set default value for To field if it's empty
49: 		if qr.To == "" {
50: 			quickRanges[i].To = "now"
51: 		}
52: 	}
53: 
54: 	cfg.QuickRanges = quickRanges
55: 
56: 	return nil
57: }
