  "summary": "Grafana's configuration system is implemented across ~30 Go source files in pkg/setting/ plus pkg/api/admin.go. The four requested capabilities are: (1) INI parsing via gopkg.in/ini.v1 orchestrated in setting.go; (2) env-var overrides via GF_<SECTION>_<KEY> applied in applyEnvVariableOverrides and DynamicSection; (3) per-section defaults declared in conf/defaults.ini and applied via MustString/MustBool/MustInt calls in each readXxx function; (4) sensitive-value masking via RedactedValue/RedactedURL called in OSSImpl.Current() before the /api/admin/settings response is built.",
  "features": {
    "ini_file_parsing": {
      "description": "INI files are parsed using the gopkg.in/ini.v1 library. The main orchestration lives in pkg/setting/setting.go. conf/defaults.ini is the canonical source of all default values.",
      "default_values_file": "conf/defaults.ini",
      "files": [
        {
          "path": "pkg/setting/setting.go",
          "functions": [
            {
              "name": "loadConfiguration",
              "line": 963,
              "description": "Top-level config load chain: reads conf/defaults.ini via ini.Load(), applies CLI default props, loads custom.ini via loadSpecifiedConfigFile(), applies env overrides, applies CLI overrides, then expands variable references."
            },
            {
              "name": "loadSpecifiedConfigFile",
              "line": 922,
              "description": "Loads the user-supplied or default custom.ini config file via ini.Load(), then merges every section/key into the master parsed file, overwriting defaults."
            },
            {
              "name": "parseINIFile",
              "line": 1165,
              "description": "Receives the fully-merged *ini.File and dispatches to all readXxx section readers (readServerSettings, readSecuritySettings, readAuthSettings, readPluginSettings, etc.) to populate the Cfg struct."
            },
            {
              "name": "NewCfgFromBytes",
              "line": 1100,
              "description": "Convenience constructor: parses a raw []byte as an INI file via ini.Load() and delegates to NewCfgFromINIFile."
            },
            {
              "name": "NewCfgFromINIFile",
              "line": 1116,
              "description": "Convenience constructor: accepts an already-parsed *ini.File and calls parseINIFile directly, skipping the full load chain."
            },
            {
              "name": "valueAsString",
              "line": 1453,
              "description": "Helper that wraps section.Key(keyName).MustString(defaultValue), providing the per-key default-value mechanism used throughout all readXxx functions."
            },
            {
              "name": "Load",
              "line": 1138,
              "description": "Public entry point: calls loadConfiguration then parseINIFile, then LogConfigSources."
            }
          ]
        },
        {
          "path": "pkg/setting/setting_unified_storage.go",
          "functions": [
            {
              "name": "setUnifiedStorageConfig",
              "line": 16,
              "description": "Iterates all INI sections with prefix 'unified_storage.' to build per-resource DualWriter config maps."
            }
          ]
        },
        {
          "path": "pkg/setting/setting_time_picker.go",
          "functions": [
            {
              "name": "readTimePicker",
              "line": 22,
              "description": "Reads [time_picker] section; parses quick_ranges JSON value from the INI key; sets default To='now' for any range missing it."
            }
          ]
        }
      ]
    },
    "environment_variable_overrides": {
      "description": "Environment variables of the form GF_<SECTION>_<KEY> (dots and hyphens in section names become underscores, all uppercased) override any INI value. There are two mechanisms: (a) batch override at load time via applyEnvVariableOverrides; (b) per-key runtime override via DynamicSection/SectionWithEnvOverrides used by individual readXxx functions. Value references of the form ${VAR} or $__env{VAR} in INI values are expanded by expandConfig.",
      "files": [
        {
          "path": "pkg/setting/setting.go",
          "functions": [
            {
              "name": "EnvKey",
              "line": 855,
              "description": "Converts a section name and key name to the canonical GF_<SECTION>_<KEY> environment variable name: dots and hyphens become underscores, everything uppercased."
            },
            {
              "name": "applyEnvVariableOverrides",
              "line": 744,
              "description": "Iterates every section and key in the parsed INI file; for each key constructs the GF_* env var name via EnvKey(), reads os.Getenv(), and if non-empty calls key.SetValue() to override the INI value. Also records the override (with value redacted) in cfg.appliedEnvOverrides."
            },
            {
              "name": "DynamicSection.Key",
              "line": 1576,
