            },
            {
              "name": "SectionWithEnvOverrides",
              "line": 0,
              "description": "Returns a DynamicSection wrapper around a raw *ini.Section so that individual readXxx functions get live env-var overrides at parse time without re-running the full batch override."
            },
            {
              "name": "applyCommandLineDefaultProperties",
              "line": 863,
              "description": "Applies CLI args of the form 'default.<section>.<key>=<value>' to the defaults layer before the custom config file is loaded."
            },
            {
              "name": "applyCommandLineProperties",
              "line": 878,
              "description": "Applies CLI args of the form 'cfg:<section>.<key>=<value>' after env overrides, giving them highest precedence."
            }
          ]
