    "sensitive_value_masking": {
      "description": "Sensitive config values are masked at two points: (1) at load time in applyEnvVariableOverrides/applyCommandLineDefaultProperties when logging applied overrides; (2) at read time in OSSImpl.Current() which is called by AdminGetSettings for every /api/admin/settings request. RedactedValue() matches key names against a list of sensitive patterns (PASSWORD, SECRET, PRIVATE_KEY, CERTIFICATE, ACCOUNT_KEY, ENCRYPTION_KEY, VAULT_TOKEN, CLIENT_SECRET, ENTERPRISE_LICENSE, API_DB_PASS, and several *_TOKEN$ patterns) and returns the constant RedactedPassword string. RedactedURL() masks passwords embedded in URL userinfo fields. Three key names are explicitly exempted from masking: RUDDERSTACK, APPLICATION_INSIGHTS, SENTRY.",
      "redacted_password_constant": "RedactedPassword",
      "sensitive_patterns": [
        "PASSWORD",
        "SECRET",
        "PROVIDER_CONFIG",
        "PRIVATE_KEY",
        "SECRET_KEY",
        "CERTIFICATE",
        "ACCOUNT_KEY",
        "ENCRYPTION_KEY",
        "VAULT_TOKEN",
        "CLIENT_SECRET",
        "ENTERPRISE_LICENSE",
        "API_DB_PASS",
        "^TOKEN$",
        "ID_FORWARDING_TOKEN$",
        "AUTHENTICATION_TOKEN$",
        "AUTH_TOKEN$",
        "RENDERER_TOKEN$",
        "API_TOKEN$",
        "WEBHOOK_TOKEN$",
        "INSTALL_TOKEN$"
      ],
      "masking_exceptions": [
        "RUDDERSTACK",
        "APPLICATION_INSIGHTS",
        "SENTRY"
      ],
      "files": [
        {
          "path": "pkg/setting/setting.go",
          "functions": [
            {
              "name": "RedactedValue",
              "line": 660,
              "description": "Core masking function. Uppercases the key name, checks it against all sensitive patterns via regexp.MatchString, returns RedactedPassword constant if matched. Checks exception list (RUDDERSTACK, APPLICATION_INSIGHTS, SENTRY) to pass values through unmasked. Falls through to RedactedURL for URL password masking."
            },
            {
              "name": "RedactedURL",
              "line": 711,
              "description": "Parses the value as a URL (or comma/space-separated list of URLs), calls url.Redacted() on each to replace any userinfo password with '***', and reassembles the list. Returns error if value is not a valid URL, causing RedactedValue to return the raw value."
            },
            {
              "name": "applyEnvVariableOverrides",
              "line": 744,
              "description": "Calls RedactedValue(envKey, envValue) when recording applied env overrides in cfg.appliedEnvOverrides, so sensitive values are never logged in plaintext."
            },
            {
              "name": "applyCommandLineDefaultProperties",
              "line": 863,
              "description": "Calls RedactedValue(keyString, value) when recording applied CLI default overrides in cfg.appliedCommandLineProperties."
            }
          ]
        },
